import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate, useParams } from 'react-router-dom';

const ResetPassword = () => {
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();
    const { token } = useParams();

    const handleResetPassword = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setMessage('');

        if (!newPassword || !confirmPassword) {
            setError('Please fill in all fields');
            setLoading(false);
            return;
        }

        if (newPassword.length < 6) {
            setError('Password must be at least 6 characters long');
            setLoading(false);
            return;
        }

        if (newPassword !== confirmPassword) {
            setError('Passwords do not match');
            setLoading(false);
            return;
        }

        try {
            const { data } = await API.post('/auth/reset-password', { 
                token, 
                newPassword 
            });
            setMessage(data.message || 'Password reset successfully!');
            setNewPassword('');
            setConfirmPassword('');
            
            setTimeout(() => {
                navigate('/');
            }, 2000);
        } catch (err) {
            const errorMsg = err.response?.data?.message || 'Failed to reset password. Please try again.';
            setError(errorMsg);
            console.error('Reset password error:', errorMsg);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');
                @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&display=swap');
                
                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
                }
                
                .cyber-grid {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    background: 
                        linear-gradient(90deg, rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px,
                        linear-gradient(rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px;
                    z-index: 1;
                    animation: gridMove 40s linear infinite;
                }
                
                @keyframes gridMove {
                    0% { transform: translate(0, 0); }
                    100% { transform: translate(50px, 50px); }
                }
                
                .orb-container {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    overflow: hidden;
                    z-index: 2;
                }
                
                .glow-orb {
                    position: absolute;
                    border-radius: 50%;
                    filter: blur(60px);
                    opacity: 0.4;
                }
                
                .orb-1 {
                    width: 600px;
                    height: 600px;
                    background: radial-gradient(circle at center, #00d4ff 0%, #0072ff 70%, transparent 100%);
                    top: -300px;
                    right: -300px;
                    animation: floatOrb 25s ease-in-out infinite;
                }
                
                .orb-2 {
                    width: 500px;
                    height: 500px;
                    background: radial-gradient(circle at center, #ff0080 0%, #9d00ff 70%, transparent 100%);
                    bottom: -250px;
                    left: -250px;
                    animation: floatOrb 30s ease-in-out infinite reverse;
                }
                
                @keyframes floatOrb {
                    0%, 100% {
                        transform: translate(0, 0) scale(1);
                    }
                    33% {
                        transform: translate(100px, -100px) scale(1.1);
                    }
                    66% {
                        transform: translate(-100px, 100px) scale(0.9);
                    }
                }
                
                .login-card-wrapper {
                    position: relative;
                    z-index: 10;
                    background: rgba(10, 15, 30, 0.7);
                    backdrop-filter: blur(30px);
                    border: 1px solid rgba(0, 210, 255, 0.2);
                    border-radius: 32px;
                    padding: 60px 50px;
                    width: 100%;
                    max-width: 480px;
                    box-shadow: 
                        0 25px 100px rgba(0, 112, 255, 0.15),
                        0 0 200px rgba(0, 210, 255, 0.05),
                        inset 0 0 100px rgba(0, 210, 255, 0.05);
                    animation: cardAppear 0.8s cubic-bezier(0.4, 0, 0.2, 1);
                    overflow: hidden;
                }
                
                .login-card-wrapper::before {
                    content: '';
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    height: 3px;
                    background: linear-gradient(90deg, #00d4ff, #0072ff, #ff0080, #9d00ff);
                }
                
                @keyframes cardAppear {
                    0% {
                        opacity: 0;
                        transform: translateY(50px) scale(0.95);
                    }
                    100% {
                        opacity: 1;
                        transform: translateY(0) scale(1);
                    }
                }
                
                .login-header {
                    text-align: center;
                    margin-bottom: 40px;
                }
                
                .brand-icon {
                    width: 80px;
                    height: 80px;
                    background: linear-gradient(135deg, #00d4ff, #0072ff);
                    border-radius: 20px;
                    margin: 0 auto 25px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 36px;
                    color: white;
                    box-shadow: 0 15px 40px rgba(0, 112, 255, 0.4);
                    transform: rotate(45deg);
                }
                
                .brand-icon span {
                    transform: rotate(-45deg);
                    font-weight: 800;
                }
                
                .login-title {
                    font-size: 3rem;
                    font-weight: 900;
                    background: linear-gradient(135deg, #00d4ff, #0072ff, #9d00ff);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    background-clip: text;
                    margin-bottom: 12px;
                    letter-spacing: -2px;
                    font-family: 'Space Grotesk', sans-serif;
                }
                
                .login-subtitle {
                    color: #94a3b8;
                    font-size: 0.95rem;
                    font-weight: 500;
                    letter-spacing: 2px;
                    text-transform: uppercase;
                }
                
                .form-container {
                    display: flex;
                    flex-direction: column;
                    gap: 28px;
                    margin-bottom: 40px;
                }
                
                .input-group {
                    position: relative;
                }
                
                .input-label {
                    display: block;
                    color: #cbd5e1;
                    margin-bottom: 12px;
                    font-size: 0.9rem;
                    font-weight: 600;
                    letter-spacing: 1px;
                    text-transform: uppercase;
                    display: flex;
                    align-items: center;
                    gap: 8px;
                }
                
                .input-field {
                    width: 100%;
                    padding: 18px 20px;
                    background: rgba(20, 25, 45, 0.6);
                    border: 2px solid rgba(255, 255, 255, 0.1);
                    border-radius: 16px;
                    color: white;
                    font-size: 1rem;
                    font-weight: 500;
                    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
                }
                
                .input-field:focus {
                    outline: none;
                    border-color: #00d4ff;
                    background: rgba(20, 25, 45, 0.9);
                    box-shadow: 0 0 0 4px rgba(0, 212, 255, 0.15);
                }
                
                .login-btn {
                    padding: 18px 30px;
                    background: linear-gradient(135deg, #0072ff 0%, #00d4ff 100%);
                    border: none;
                    border-radius: 16px;
                    color: white;
                    font-size: 1rem;
                    font-weight: 700;
                    cursor: pointer;
                    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
                    text-transform: uppercase;
                    letter-spacing: 1.5px;
                    position: relative;
                    overflow: hidden;
                    box-shadow: 0 15px 50px rgba(0, 112, 255, 0.3);
                }
                
                .login-btn:hover:not(:disabled) {
                    transform: translateY(-5px);
                    box-shadow: 0 25px 60px rgba(0, 112, 255, 0.4);
                }
                
                .login-btn:disabled {
                    opacity: 0.6;
                    cursor: not-allowed;
                }
                
                .security-badge {
                    text-align: center;
                    padding: 20px;
                    background: rgba(0, 212, 255, 0.05);
                    border-radius: 16px;
                    border: 1px solid rgba(0, 212, 255, 0.1);
                    color: #00d4ff;
                    font-size: 0.85rem;
                    font-weight: 600;
                    letter-spacing: 1.5px;
                    text-transform: uppercase;
                }
                
                @media (max-width: 640px) {
                    .login-card-wrapper {
                        padding: 40px 30px;
                        margin: 20px;
                        max-width: calc(100% - 40px);
                    }
                    .login-title {
                        font-size: 2.2rem;
                    }
                }
            `}</style>

            <div className="cyber-grid"></div>
            
            <div className="orb-container">
                <div className="glow-orb orb-1"></div>
                <div className="glow-orb orb-2"></div>
            </div>

            <div className="login-card-wrapper">
                <div className="login-header">
                    <div className="brand-icon">
                        <span>🔐</span>
                    </div>
                    <div className="login-title">Reset Password</div>
                    <div className="login-subtitle">Create a new secure password</div>
                </div>
                
                <form onSubmit={handleResetPassword} className="form-container">
                    {error && (
                        <div style={{
                            padding: '12px 16px',
                            backgroundColor: 'rgba(239, 68, 68, 0.1)',
                            border: '1px solid rgba(239, 68, 68, 0.3)',
                            borderRadius: '8px',
                            color: '#ff6b6b',
                            fontSize: '0.9rem',
                            marginBottom: '10px'
                        }}>
                            ⚠️ {error}
                        </div>
                    )}

                    {message && (
                        <div style={{
                            padding: '12px 16px',
                            backgroundColor: 'rgba(34, 197, 94, 0.1)',
                            border: '1px solid rgba(34, 197, 94, 0.3)',
                            borderRadius: '8px',
                            color: '#22c55e',
                            fontSize: '0.9rem',
                            marginBottom: '10px'
                        }}>
                            ✅ {message}
                        </div>
                    )}

                    <div className="input-group">
                        <label className="input-label">
                            <span>🔐</span>
                            New Password
                        </label>
                        <input 
                            type="password" 
                            className="input-field"
                            placeholder="••••••••••••" 
                            value={newPassword}
                            onChange={e => setNewPassword(e.target.value)} 
                            required 
                        />
                    </div>
                    
                    <div className="input-group">
                        <label className="input-label">
                            <span>🔒</span>
                            Confirm Password
                        </label>
                        <input 
                            type="password" 
                            className="input-field"
                            placeholder="••••••••••••" 
                            value={confirmPassword}
                            onChange={e => setConfirmPassword(e.target.value)} 
                            required 
                        />
                    </div>
                    
                    <button type="submit" className="login-btn" disabled={loading}>
                        {loading ? '⏳ Resetting...' : '✅ Reset Password'}
                    </button>
                </form>
                
                <div className="security-badge">
                    Secure Password Reset Portal
                </div>
            </div>
        </div>
    );
};

const styles = {
    loginPage: {
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'linear-gradient(135deg, #000814 0%, #001233 30%, #000814 100%)',
        overflow: 'hidden',
        position: 'relative',
        padding: '20px',
    },
};

export default ResetPassword;
